/* ── Helpers ── */
  const $ = id => document.getElementById(id);

  function openAboutModal()  { $('aboutModal').classList.add('active'); }
  function closeAboutModal() { $('aboutModal').classList.remove('active'); }
  function showComingSoonModal() { $('comingSoonModal').classList.add('active'); }
  function closeModal() { $('comingSoonModal').classList.remove('active'); }

  $('aboutModal').addEventListener('click', function(e)      { if(e.target===this) closeAboutModal(); });
  $('comingSoonModal').addEventListener('click', function(e) { if(e.target===this) closeModal(); });
  $('instructionsModal').addEventListener('click', function(e) { if(e.target===this) closeInstructionsModal(); });

  function openInstructionsModal()  { $('instructionsModal').classList.add('active'); }
  function closeInstructionsModal() { $('instructionsModal').classList.remove('active'); }

  function switchInstrTab(tabId, btn) {
    document.querySelectorAll('.instr-section').forEach(s => s.classList.remove('active'));
    document.querySelectorAll('.instr-tab').forEach(b => b.classList.remove('active'));
    document.getElementById('instr-' + tabId).classList.add('active');
    btn.classList.add('active');
  }

  /* ── Active users widget ── */
  window.addEventListener('load', function(){
    if(typeof ActiveUsersWidget !== 'undefined') ActiveUsersWidget.init({position:'corner'});
  });

  /* ── Welcome Banner – reads window._sbUser + token cookie, calls REST directly ── */
  const SB_URL = 'https://iygwhapcpdmsasqlfelv.supabase.co';
  const SB_KEY = 'sb_publishable_rD9naqrpu1dI-iwchAS0GQ_JkgGysqP';

  function getCookieVal(name) {
    const v = `; ${document.cookie}`;
    const p = v.split(`; ${name}=`);
    if (p.length === 2) return p.pop().split(';').shift();
    return null;
  }

  async function loadUserProfile() {
    $('welcomeSkeleton').style.display = 'block';
    try {
      const user  = window._sbUser;
      const token = getCookieVal('sb-access-token');
      if (!user || !token) { $('welcomeSkeleton').style.display = 'none'; return; }

      // استدعاء REST مباشر مع Authorization header عشان يتجاوز RLS
      const res = await fetch(
        `${SB_URL}/rest/v1/profiles?select=full_name,role&id=eq.${user.id}&limit=1`,
        {
          headers: {
            'apikey':        SB_KEY,
            'Authorization': `Bearer ${token}`,
            'Accept':        'application/json'
          }
        }
      );

      $('welcomeSkeleton').style.display = 'none';

      if (!res.ok) { console.warn('WE-Core: profiles', res.status, await res.text()); return; }

      const rows    = await res.json();
      const profile = rows[0] || null;
      if (!profile) return;

      // اعرض الاسم والمسمى الوظيفي
      $('welcomeName').textContent     = profile.full_name || user.email || 'زميلنا';
      $('welcomeJobTitle').textContent = profile.role || '—';

      if (!profile.role) document.querySelector('.welcome-titel').style.display = 'none';

      $('welcomeBanner').style.display = 'block';

    } catch(e) {
      $('welcomeSkeleton').style.display = 'none';
      console.warn('WE-Core: profile load failed', e);
    }
  }

  // auth.js بيبعت authSuccess بعد ما يتحقق من اليوزر ويحفظ _sbUser
  window.addEventListener('authSuccess', loadUserProfile);

