  const SECTION_ICONS = {
    root: 'fa-table-cells-large',
    عروض: 'fa-gift',
    معلومات: 'fa-circle-info',
    خدمات: 'fa-headset',
    كورسات: 'fa-graduation-cap',
    قواعد: 'fa-head-side-virus',
  };

  function highlightText(text, query) {
    if (!query) return text;
    const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    return text.replace(new RegExp('(' + escaped + ')', 'gi'), '<mark>$1</mark>');
  }

  function getSnippet(text, query) {
    const lower = text.toLowerCase();
    const idx = lower.indexOf(query.toLowerCase());
    if (idx === -1) return text.substring(0, 120) + '…';
    const start = Math.max(0, idx - 50);
    const end = Math.min(text.length, idx + 120);
    return (start > 0 ? '…' : '') + text.substring(start, end) + (end < text.length ? '…' : '');
  }

  function handleSearch(val){
    const q = val.trim().toLowerCase();
    document.getElementById('searchClear').style.display = q ? 'block' : 'none';

    // Filter main cards
    const links = document.querySelectorAll('#cardsGrid .card-link');
    let visible = 0;
    links.forEach(link => {
      const text = link.innerText.toLowerCase();
      const match = !q || text.includes(q);
      link.style.display = match ? '' : 'none';
      if(match) visible++;
    });
    document.getElementById('noResult').style.display = (visible === 0 && !q) ? 'block' : 'none';

    // Deep search
    const panel = document.getElementById('deepSearchResults');
    if (!q || q.length < 2) {
      panel.style.display = 'none';
      return;
    }

    const results = SEARCH_INDEX.filter(p =>
      p.title.toLowerCase().includes(q) || p.text.toLowerCase().includes(q)
    ).slice(0, 15);

    if (results.length === 0) {
      panel.innerHTML = '<div class="deep-results-header"><i class="fa-solid fa-face-frown-open"></i> مفيش نتائج، جرب كلمة تانية</div>';
      panel.style.display = 'block';
      return;
    }

    const icon = SECTION_ICONS;
    let html = `<div class="deep-results-header"><i class="fa-solid fa-magnifying-glass"></i> ${results.length} نتيجة في كل الصفحات</div>`;
    results.forEach(r => {
      const iconClass = icon[r.section] || 'fa-file';
      const snippet = getSnippet(r.text, q);
      const hTitle = highlightText(r.title, val.trim());
      const hSnippet = highlightText(snippet, val.trim());
      html += `<a href="${r.href}" class="deep-result-item">
        <div class="dr-icon"><i class="fa-solid ${iconClass}"></i></div>
        <div class="dr-body">
          <div class="dr-title">${hTitle}</div>
          <span class="dr-section">${r.section === 'root' ? 'رئيسي' : r.section}</span>
          <div class="dr-snippet">${hSnippet}</div>
        </div>
      </a>`;
    });

    panel.innerHTML = html;
    panel.style.display = 'block';
  }

  function clearSearch(){
    const inp = document.getElementById('siteSearch');
    inp.value = '';
    handleSearch('');
    inp.focus();
    document.getElementById('deepSearchResults').style.display = 'none';
  }
